import type { FlashcardData } from "./flashcards-rpn";

export const rnRespRenalFlashcards: FlashcardData[] = [
  // ============================================================
  // PULMONARY HYPERTENSION (30 cards)
  // ============================================================
  { id: "rn-ph-1", type: "question", question: "A patient on continuous IV epoprostenol for PAH reports that the pump has alarmed and stopped. What is the PRIORITY action?", options: ["Notify the provider and document the event", "Restart the pump or switch to the backup pump immediately", "Administer sublingual nitroglycerin", "Assess vital signs and recheck in 15 minutes"], correctIndex: 1, answer: "Epoprostenol has a half-life of 3-5 minutes. Abrupt discontinuation causes fatal rebound pulmonary hypertension. The nurse must immediately restart or switch to backup pump.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ph-2", type: "question", question: "What is the gold standard diagnostic test for confirming pulmonary hypertension?", options: ["Echocardiogram", "CT pulmonary angiography", "Right heart catheterization", "Chest X-ray"], correctIndex: 2, answer: "Right heart catheterization directly measures pulmonary artery pressures. PH is defined as mPAP >20 mmHg. Echo is used for screening but RHC is definitive.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-3", type: "question", question: "A PAH patient tests positive on vasoreactivity testing during RHC. Which medication class is indicated?", options: ["Prostacyclin analogs", "PDE5 inhibitors", "Calcium channel blockers", "Endothelin receptor antagonists"], correctIndex: 2, answer: "Only ~10% of PAH patients are vasoreactive. A positive test (mPAP drop >10 to <40) identifies those who respond to calcium channel blockers (nifedipine, diltiazem).", category: "Respiratory", difficulty: 3 },
  { id: "rn-ph-4", type: "question", question: "What WHO functional class finding indicates the MOST severe PAH requiring IV prostacyclin?", options: ["FC I: No limitation of physical activity", "FC II: Slight limitation with ordinary activity", "FC III: Marked limitation with less than ordinary activity", "FC IV: Inability to perform any activity without symptoms; dyspnea at rest"], correctIndex: 3, answer: "WHO FC IV indicates severe disease with symptoms at rest. IV prostacyclin (epoprostenol) is first-line for FC IV or rapidly progressive PAH due to its potent vasodilatory and antiproliferative effects.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-5", type: "question", question: "Which side effect should the nurse monitor for in a patient taking bosentan (Tracleer) for PAH?", options: ["Renal failure", "Hepatotoxicity requiring monthly LFTs", "Pulmonary fibrosis", "Bone marrow suppression"], correctIndex: 1, answer: "Bosentan (endothelin receptor antagonist) is hepatotoxic. Monthly liver function tests are mandatory. Hold if transaminases exceed 5x ULN. It is also a Category X teratogen.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-6", type: "question", question: "Syncope on exertion in a PAH patient indicates what?", options: ["Normal exercise response", "Severely reduced cardiac output and increased risk of sudden death", "Medication side effect only", "Dehydration"], correctIndex: 1, answer: "Exertional syncope in PAH indicates that the right ventricle cannot increase cardiac output to meet exercise demands, causing cerebral hypoperfusion. This signals severe disease requiring urgent therapy escalation.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-7", type: "question", question: "Why is pregnancy contraindicated in severe PAH?", options: ["Medications are teratogenic only", "Maternal mortality is 30-50% due to hemodynamic stress on the failing RV", "Pregnancy has no effect on PAH", "Fetal growth restriction is the only concern"], correctIndex: 1, answer: "Pregnancy increases blood volume by 40-50%, dramatically increasing RV workload. The fixed pulmonary vascular resistance cannot accommodate this increase, leading to RV failure. Maternal mortality reaches 30-50%.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-8", type: "question", question: "A loud P2 on cardiac auscultation in a patient with dyspnea suggests what?", options: ["Mitral valve stenosis", "Elevated pulmonary artery pressure", "Aortic stenosis", "Tricuspid valve prolapse"], correctIndex: 1, answer: "A loud pulmonic component of S2 (P2) reflects elevated pulmonary artery pressure causing forceful closure of the pulmonic valve. This is an important auscultatory finding in pulmonary hypertension.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-9", type: "question", question: "Which PH group should NOT receive PAH-specific vasodilator therapy?", options: ["Group 1 (PAH)", "Group 2 (left heart disease)", "Group 4 (chronic thromboembolic)", "Group 5 (multifactorial)"], correctIndex: 1, answer: "Group 2 PH is caused by left heart disease (HF, valvular). PAH vasodilators can worsen pulmonary edema by increasing blood flow to an already overloaded left heart. Treatment should target the underlying cardiac condition.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ph-10", type: "question", question: "What finding on echocardiogram suggests pulmonary hypertension?", options: ["Left ventricular hypertrophy", "RV dilation with interventricular septum bowing toward the LV", "Mitral valve prolapse", "Left atrial enlargement"], correctIndex: 1, answer: "In PH, elevated RV pressure causes dilation and the interventricular septum bows toward the LV (D-shaped LV), impairing LV filling. Tricuspid regurgitation and elevated RVSP are also seen.", category: "Respiratory", difficulty: 2 },

  // ============================================================
  // ARDS (30 cards)
  // ============================================================
  { id: "rn-ards-1", type: "question", question: "What is the PaO2/FiO2 ratio cutoff for severe ARDS per Berlin criteria?", options: ["<300", "<200", "<100", "<150"], correctIndex: 2, answer: "Berlin criteria: mild 200-300, moderate 100-200, severe <100. A PaO2/FiO2 <100 indicates severe ARDS requiring advanced interventions including prone positioning and possibly ECMO.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-2", type: "question", question: "What tidal volume should be used for lung-protective ventilation in ARDS?", options: ["10-12 mL/kg actual body weight", "8 mL/kg ideal body weight", "6 mL/kg ideal body weight", "4 mL/kg actual body weight"], correctIndex: 2, answer: "The ARDSNet protocol demonstrated 22% mortality reduction with 6 mL/kg ideal body weight (IBW). IBW is calculated from height, not actual weight. Plateau pressure must also be <30 cmH2O.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-3", type: "question", question: "What is the most common cause of ARDS?", options: ["Aspiration", "Trauma", "Sepsis (40% of cases)", "Near-drowning"], correctIndex: 2, answer: "Sepsis accounts for approximately 40% of ARDS cases. The systemic inflammatory response causes diffuse alveolar-capillary membrane damage. Pneumonia is the second most common cause.", category: "Respiratory", difficulty: 1 },
  { id: "rn-ards-4", type: "question", question: "How does prone positioning improve oxygenation in ARDS?", options: ["It increases tidal volume", "It redistributes perfusion to better-ventilated anterior lung regions, improving V/Q matching", "It reduces heart rate", "It increases surfactant production"], correctIndex: 1, answer: "Prone positioning redistributes perfusion from the dependent (now anterior) lung regions to better-ventilated areas, improving V/Q matching. The PROSEVA trial showed mortality benefit with 12-16 hours/day in moderate-severe ARDS.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-5", type: "question", question: "A patient on mechanical ventilation for ARDS suddenly desaturates with absent left breath sounds and tracheal deviation to the right. What complication occurred?", options: ["Mucus plug", "Left tension pneumothorax", "Right mainstem intubation", "Worsening ARDS"], correctIndex: 1, answer: "Sudden desaturation + absent breath sounds on one side + tracheal deviation AWAY from the affected side = tension pneumothorax. PEEP and positive pressure ventilation increase barotrauma risk. Immediate needle decompression is needed.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-6", type: "question", question: "What differentiates ARDS from cardiogenic pulmonary edema?", options: ["Bilateral infiltrates on CXR (present in both)", "PCWP: ARDS <18 mmHg vs cardiogenic >18 mmHg", "Tachypnea (present in both)", "Hypoxemia (present in both)"], correctIndex: 1, answer: "PCWP <18 mmHg distinguishes ARDS (non-cardiogenic) from cardiogenic pulmonary edema (>18). Both show bilateral infiltrates, hypoxemia, and tachypnea. BNP is also normal/low in ARDS.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-7", type: "question", question: "Why is a conservative fluid strategy used in ARDS after initial resuscitation?", options: ["To increase cardiac output", "To minimize pulmonary edema through the damaged alveolar-capillary membrane", "To promote diuresis of toxins", "To increase blood pressure"], correctIndex: 1, answer: "The FACTT trial showed that a conservative fluid strategy reduces ventilator days and ICU stay. With damaged alveolar-capillary membranes, excess fluid readily leaks into alveoli, worsening gas exchange.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-8", type: "question", question: "What is the hallmark pathological finding in ARDS during the exudative phase?", options: ["Pulmonary fibrosis", "Hyaline membrane formation along alveolar walls", "Bronchial smooth muscle hypertrophy", "Pleural calcification"], correctIndex: 1, answer: "Hyaline membranes form from fibrin and necrotic cellular debris along denuded alveolar walls. This is the pathological hallmark of diffuse alveolar damage in the exudative phase (days 1-7) of ARDS.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-9", type: "question", question: "Before prone positioning an ARDS patient, what nursing assessment is MOST important?", options: ["Verify IV fluid rate", "Ensure endotracheal tube and all lines are secured; check pressure points", "Obtain a chest X-ray", "Check blood glucose level"], correctIndex: 1, answer: "Before prone positioning, secure the ETT, all IV lines, arterial lines, and Foley. Protect pressure points (face, chest, pelvis, knees). The turning procedure requires a coordinated team effort.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-10", type: "question", question: "What is the target plateau pressure in ARDS to prevent ventilator-induced lung injury?", options: ["<20 cmH2O", "<30 cmH2O", "<40 cmH2O", "<50 cmH2O"], correctIndex: 1, answer: "Plateau pressure must be maintained <30 cmH2O to prevent alveolar overdistension (volutrauma) and ventilator-induced lung injury. This is checked by performing an inspiratory hold on the ventilator.", category: "Respiratory", difficulty: 2 },

  // ============================================================
  // COPD (25 cards)
  // ============================================================
  { id: "rn-copd-1", type: "question", question: "A COPD patient on 2L O2 has SpO2 86%. The nurse increases to 6L via simple mask. The patient becomes drowsy with ABG showing PaCO2 88 mmHg. What happened?", options: ["Oxygen toxicity", "CO2 narcosis from suppression of hypoxic respiratory drive", "Pulmonary embolism", "Pneumothorax"], correctIndex: 1, answer: "Chronic CO2 retainers in COPD rely on hypoxic drive for breathing. High-flow O2 eliminates this drive, causing hypoventilation and CO2 narcosis. Target SpO2 for COPD is 88-92%.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-2", type: "question", question: "What is the ONLY intervention proven to slow FEV1 decline and reduce mortality in COPD?", options: ["Inhaled corticosteroids", "Long-acting bronchodilators", "Smoking cessation", "Pulmonary rehabilitation"], correctIndex: 2, answer: "Smoking cessation is the ONLY intervention that changes the natural history of COPD by slowing the accelerated decline in FEV1. All other treatments improve symptoms but do not alter disease progression.", category: "Respiratory", difficulty: 1 },
  { id: "rn-copd-3", type: "question", question: "What spirometry finding confirms the diagnosis of COPD?", options: ["FEV1/FVC >0.70", "FEV1/FVC <0.70 after bronchodilator", "FVC <80% predicted", "Peak flow >400 L/min"], correctIndex: 1, answer: "FEV1/FVC ratio <0.70 after bronchodilator administration confirms airflow obstruction in COPD. The incomplete reversibility differentiates COPD from asthma (which shows significant reversibility).", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-4", type: "question", question: "A patient with suspected COPD is 35 years old and has never smoked. What should the nurse anticipate testing for?", options: ["Lung cancer screening", "Alpha-1 antitrypsin deficiency", "Cystic fibrosis", "Tuberculosis"], correctIndex: 1, answer: "Alpha-1 antitrypsin deficiency should be suspected in young, non-smoking COPD patients. It causes panacinar emphysema predominantly in the lung bases. All COPD patients should be screened at least once.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-5", type: "question", question: "What is the classic 'pink puffer' phenotype in COPD?", options: ["Chronic bronchitis with cyanosis and edema", "Emphysema with thin body habitus, dyspnea, and preserved oxygenation", "Asthma with wheezing", "Pulmonary fibrosis with clubbing"], correctIndex: 1, answer: "Pink puffer = emphysema phenotype: thin, barrel chest, pursed-lip breathing, dyspneic but relatively well-oxygenated (maintains PaO2 through hyperventilation). Blue bloater = chronic bronchitis with cyanosis and edema.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-6", type: "question", question: "Why does pursed-lip breathing help COPD patients?", options: ["It increases oxygen absorption", "It creates auto-PEEP that prevents small airway collapse during expiration", "It reduces heart rate", "It clears mucus from airways"], correctIndex: 1, answer: "Pursed-lip breathing creates back-pressure (auto-PEEP) during expiration, splinting small airways open and preventing premature collapse. This reduces air trapping and improves CO2 elimination.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-7", type: "question", question: "A COPD patient presents with increased dyspnea, increased sputum volume, and purulent (green) sputum. What does this triad indicate?", options: ["Stable COPD", "Acute exacerbation of COPD", "Lung cancer", "Pneumothorax"], correctIndex: 1, answer: "The Anthonisen criteria for COPD exacerbation: increased dyspnea + increased sputum volume + increased sputum purulence. Presence of all three indicates a type 1 (most severe) exacerbation likely requiring antibiotics.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-8", type: "question", question: "Which COPD complication results from chronic hypoxic pulmonary vasoconstriction?", options: ["Left heart failure", "Cor pulmonale (right heart failure)", "Atrial fibrillation", "Aortic stenosis"], correctIndex: 1, answer: "Chronic hypoxemia causes sustained pulmonary vasoconstriction, increasing pulmonary vascular resistance. The right ventricle hypertrophies and eventually fails (cor pulmonale), causing JVD, hepatomegaly, and peripheral edema.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-9", type: "question", question: "Why is digital clubbing NOT typical of COPD?", options: ["COPD doesn't cause hypoxemia", "Clubbing in a COPD patient should prompt investigation for lung cancer or bronchiectasis", "Clubbing only occurs with cardiac disease", "All COPD patients have clubbing"], correctIndex: 1, answer: "Clubbing is not a typical feature of COPD. If present, it should raise suspicion for comorbid lung cancer or bronchiectasis. Its presence warrants further investigation.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-10", type: "question", question: "What is the target SpO2 for supplemental oxygen therapy in a COPD patient?", options: ["95-100%", "92-96%", "88-92%", "80-85%"], correctIndex: 2, answer: "Target SpO2 for COPD is 88-92%. Higher targets risk suppressing the hypoxic respiratory drive in chronic CO2 retainers, leading to hypoventilation and CO2 narcosis.", category: "Respiratory", difficulty: 1 },

  // ============================================================
  // ASTHMA (25 cards)
  // ============================================================
  { id: "rn-asth-1", type: "question", question: "During a severe asthma attack, wheezing suddenly stops and the patient becomes drowsy. ABG shows rising PaCO2. What does this indicate?", options: ["Improving bronchospasm", "Impending respiratory failure - prepare for intubation", "Resolution of the attack", "Need for higher-dose bronchodilator only"], correctIndex: 1, answer: "Silent chest = air movement so poor that wheezing cannot be generated. Combined with rising PaCO2 (should be LOW in acute asthma from hyperventilation) and drowsiness = respiratory muscle fatigue and impending arrest.", category: "Respiratory", difficulty: 3 },
  { id: "rn-asth-2", type: "question", question: "What is the Samter triad (aspirin-exacerbated respiratory disease)?", options: ["Asthma + pneumonia + COPD", "Asthma + nasal polyps + aspirin/NSAID sensitivity", "Asthma + GERD + obesity", "Asthma + eczema + food allergies"], correctIndex: 1, answer: "Samter triad: asthma + nasal polyps + aspirin/NSAID sensitivity. COX-1 inhibition by aspirin shunts arachidonic acid to the leukotriene pathway, causing severe bronchospasm. Leukotriene inhibitors (montelukast) are particularly helpful.", category: "Respiratory", difficulty: 2 },
  { id: "rn-asth-3", type: "question", question: "A patient uses their rescue albuterol inhaler 5 times per week. What does this indicate?", options: ["Well-controlled asthma", "Uncontrolled asthma requiring step-up of controller therapy", "Normal rescue inhaler use", "Need to switch to ipratropium"], correctIndex: 1, answer: "Rescue SABA use >2 days/week indicates uncontrolled asthma. Per GINA guidelines, the patient needs initiation or step-up of controller therapy (typically an inhaled corticosteroid).", category: "Respiratory", difficulty: 1 },
  { id: "rn-asth-4", type: "question", question: "What FDA boxed warning does montelukast (Singulair) carry?", options: ["Hepatotoxicity", "Neuropsychiatric effects including suicidal ideation", "QT prolongation", "Renal failure"], correctIndex: 1, answer: "Montelukast carries an FDA boxed warning for neuropsychiatric events: suicidal thoughts, depression, agitation, aggression, sleep disturbances. Monitor mood changes and educate patient/family to report symptoms.", category: "Respiratory", difficulty: 2 },
  { id: "rn-asth-5", type: "question", question: "After using an inhaled corticosteroid (ICS), the patient should:", options: ["Drink a glass of milk", "Rinse mouth with water and spit to prevent oral candidiasis", "Take a deep breath and hold for 30 seconds", "Apply an ice pack to the throat"], correctIndex: 1, answer: "Rinsing the mouth after ICS use removes residual steroid from the oropharynx, preventing oral candidiasis (thrush) and dysphonia. This is a critical patient teaching point.", category: "Respiratory", difficulty: 1 },
  { id: "rn-asth-6", type: "question", question: "What is the role of IV magnesium sulfate in status asthmaticus?", options: ["It is a first-line bronchodilator", "It inhibits calcium-mediated smooth muscle contraction for bronchodilation when SABA fails", "It replaces magnesium deficiency", "It treats associated hypertension"], correctIndex: 1, answer: "IV magnesium sulfate (2g over 20 min) causes bronchodilation by inhibiting calcium-mediated smooth muscle contraction. Used when status asthmaticus is refractory to beta-agonists and corticosteroids.", category: "Respiratory", difficulty: 3 },
  { id: "rn-asth-7", type: "question", question: "Which spirometry finding confirms reversible airway obstruction characteristic of asthma?", options: ["FEV1/FVC <0.70 with no change after bronchodilator", ">12% and >200 mL improvement in FEV1 after bronchodilator", "Reduced DLCO", "Increased residual volume only"], correctIndex: 1, answer: "Significant bronchodilator reversibility (>12% AND >200 mL improvement in FEV1) confirms reversible airway obstruction, characteristic of asthma. COPD shows minimal or incomplete reversibility.", category: "Respiratory", difficulty: 2 },
  { id: "rn-asth-8", type: "question", question: "Pulsus paradoxus >10 mmHg during an asthma attack indicates:", options: ["Normal finding", "Severe attack with significant intrathoracic pressure swings", "Cardiac tamponade", "Hypovolemia"], correctIndex: 1, answer: "Pulsus paradoxus (>10 mmHg drop in SBP during inspiration) in asthma reflects large intrathoracic pressure swings from severe airway obstruction. It indicates a severe attack requiring aggressive treatment.", category: "Respiratory", difficulty: 3 },
  { id: "rn-asth-9", type: "question", question: "What is the most effective long-term controller medication for persistent asthma?", options: ["Albuterol (SABA)", "Inhaled corticosteroid (ICS)", "Leukotriene modifier", "Theophylline"], correctIndex: 1, answer: "Inhaled corticosteroids are the cornerstone of asthma controller therapy. They reduce airway inflammation, decrease hyperresponsiveness, and prevent exacerbations more effectively than any other single agent.", category: "Respiratory", difficulty: 1 },
  { id: "rn-asth-10", type: "question", question: "In an asthma action plan, what does the RED zone indicate?", options: ["Well-controlled asthma, continue maintenance", "Caution - increase medications", "Medical emergency - peak flow <50% personal best, severe symptoms", "Seasonal allergy management"], correctIndex: 2, answer: "Red zone: PEF <50% personal best, severe dyspnea, rescue inhaler not helping. Action: use rescue inhaler immediately, take oral corticosteroid, call 911 or go to ED. This is a medical emergency.", category: "Respiratory", difficulty: 1 },

  // ============================================================
  // PULMONARY EMBOLISM (25 cards)
  // ============================================================
  { id: "rn-pe-1", type: "question", question: "What three factors comprise Virchow triad for thrombosis?", options: ["Fever, leukocytosis, tachycardia", "Venous stasis, endothelial injury, hypercoagulability", "Hypotension, bradycardia, hypothermia", "Cough, dyspnea, hemoptysis"], correctIndex: 1, answer: "Virchow triad: (1) Venous stasis (immobility), (2) Endothelial injury (surgery, trauma), (3) Hypercoagulability (malignancy, pregnancy, clotting disorders). Understanding this guides prevention strategies.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pe-2", type: "question", question: "A patient 3 days post-hip replacement develops sudden dyspnea, HR 128, SpO2 82%, and BP 76/48. What does the nurse suspect and what is the priority?", options: ["Pneumonia - obtain sputum culture", "Massive PE - high-flow O2 and activate rapid response", "Atelectasis - encourage incentive spirometry", "Anxiety attack - provide reassurance"], correctIndex: 1, answer: "Post-orthopedic surgery + sudden dyspnea + tachycardia + hypoxemia + hypotension = massive PE until proven otherwise. Priority: high-flow O2, IV access, activate rapid response, prepare for possible thrombolysis.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-3", type: "question", question: "What is the most common ECG finding in pulmonary embolism?", options: ["S1Q3T3 pattern", "ST elevation in leads II, III, aVF", "Sinus tachycardia", "Complete heart block"], correctIndex: 2, answer: "Sinus tachycardia is the most common ECG finding in PE. The classic S1Q3T3 pattern is specific but insensitive (only seen in ~20% of cases). New RBBB and T-wave inversions in V1-V4 may also occur.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-4", type: "question", question: "A negative D-dimer in a patient with LOW clinical probability effectively:", options: ["Confirms the diagnosis of PE", "Rules out PE (high negative predictive value)", "Rules out DVT only", "Has no diagnostic value"], correctIndex: 1, answer: "D-dimer is highly sensitive but not specific. A negative D-dimer in a low-probability patient (by Wells or Geneva score) has >99% negative predictive value, effectively ruling out PE without imaging.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-5", type: "question", question: "What defines a massive PE?", options: ["PE with hypoxemia only", "PE with hemodynamic instability (SBP <90 for >15 minutes)", "Any PE with elevated troponin", "PE affecting more than one lobe"], correctIndex: 1, answer: "Massive PE is defined by hemodynamic instability: systolic BP <90 mmHg for >15 minutes, requiring vasopressors, or cardiac arrest. This requires emergent thrombolysis or surgical embolectomy.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-6", type: "question", question: "What is the McConnell sign on echocardiogram?", options: ["LV hypokinesis", "RV free wall akinesis with preserved apical contractility - highly specific for PE", "Mitral valve prolapse", "Aortic root dilation"], correctIndex: 1, answer: "McConnell sign (akinetic RV free wall with preserved apical motion) is highly specific for acute PE. The RV apex is spared because it is tethered to the normally contracting LV.", category: "Respiratory", difficulty: 3 },
  { id: "rn-pe-7", type: "question", question: "Hemoptysis in a PE patient suggests:", options: ["Concurrent pneumonia", "Pulmonary infarction (lung tissue death)", "Active tuberculosis", "Esophageal bleeding"], correctIndex: 1, answer: "Hemoptysis in PE indicates pulmonary infarction - ischemic death of lung tissue distal to the occluded vessel. Pulmonary infarction occurs in about 10% of PE cases, more common in peripheral emboli.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-8", type: "question", question: "When should anticoagulation be initiated for suspected PE?", options: ["Only after CT-PA confirms PE", "While awaiting imaging if clinical suspicion is high", "After D-dimer results return", "Only after echocardiogram"], correctIndex: 1, answer: "If clinical suspicion for PE is high, anticoagulation should be initiated empirically while awaiting confirmatory imaging. Delaying treatment for diagnostic confirmation can be fatal in massive PE.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-9", type: "question", question: "What is the antidote for rivaroxaban (Xarelto)?", options: ["Protamine sulfate", "Vitamin K", "Andexanet alfa (Andexxa)", "Fresh frozen plasma"], correctIndex: 2, answer: "Andexanet alfa is the specific reversal agent for factor Xa inhibitors (rivaroxaban, apixaban). Protamine reverses heparin, vitamin K reverses warfarin.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-10", type: "question", question: "What is the indication for IVC filter placement in PE?", options: ["All PE patients", "When anticoagulation is contraindicated or PE recurs despite adequate anticoagulation", "As first-line treatment for submassive PE", "Only for pregnant patients"], correctIndex: 1, answer: "IVC filters are placed when anticoagulation is absolutely contraindicated (active hemorrhage, recent surgery) or when PE recurs despite therapeutic anticoagulation. They mechanically trap emboli from the legs.", category: "Respiratory", difficulty: 2 },

  // ============================================================
  // PNEUMONIA (25 cards)
  // ============================================================
  { id: "rn-pna-1", type: "question", question: "An 85-year-old nursing home resident presents with new confusion as the ONLY symptom. CXR shows RLL consolidation. What should the nurse recognize?", options: ["Normal age-related confusion", "Atypical pneumonia presentation in elderly - confusion may be only sign", "Delirium from medication interaction", "Sundowning phenomenon"], correctIndex: 1, answer: "In elderly patients, altered mental status may be the ONLY presenting sign of pneumonia. Fever may be absent. The nurse must recognize that new confusion in elderly warrants workup for infection.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-2", type: "question", question: "Rust-colored sputum is classic for which pneumonia pathogen?", options: ["Klebsiella pneumoniae", "Streptococcus pneumoniae", "Pseudomonas aeruginosa", "Mycoplasma pneumoniae"], correctIndex: 1, answer: "Rust-colored sputum is classic for Streptococcus pneumoniae (pneumococcal pneumonia). Currant jelly sputum = Klebsiella. Green sputum = Pseudomonas. Mycoplasma typically causes dry cough.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-3", type: "question", question: "What physical examination finding indicates lung consolidation?", options: ["Hyperresonance to percussion", "Bronchial breath sounds heard over lung periphery with egophony", "Absent breath sounds bilaterally", "Wheezing on inspiration"], correctIndex: 1, answer: "Consolidated lung transmits sound better than air-filled alveoli. Findings: bronchial breath sounds (normally tracheal only), egophony (E-to-A change), increased tactile fremitus, dullness to percussion.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-4", type: "question", question: "When should blood cultures be obtained in pneumonia?", options: ["After antibiotics have been given for 24 hours", "BEFORE starting antibiotics, but do not delay antibiotics", "Only if the patient has a central line", "Blood cultures are not needed in pneumonia"], correctIndex: 1, answer: "Blood cultures should be obtained BEFORE antibiotics when possible, but antibiotic administration should NOT be delayed beyond 1 hour to wait for cultures. Obtain cultures, then start antibiotics immediately.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-5", type: "question", question: "Which element of the VAP prevention bundle is a direct nursing responsibility?", options: ["Prescribing antibiotics", "Oral care with chlorhexidine every 2 hours and maintaining HOB 30-45 degrees", "Selecting ventilator mode", "Ordering daily sedation vacations"], correctIndex: 1, answer: "Oral care with chlorhexidine and HOB elevation 30-45 degrees are direct nursing interventions in the VAP bundle. They reduce aspiration risk and oropharyngeal colonization.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pna-6", type: "question", question: "HAP is defined as pneumonia developing:", options: ["Before hospital admission", ">=48 hours after hospital admission", "Within 24 hours of admission", "Only in ICU patients"], correctIndex: 1, answer: "Hospital-acquired pneumonia (HAP) develops >=48 hours after admission and was not incubating at admission. HAP pathogens are often more resistant (MRSA, Pseudomonas) requiring broader-spectrum antibiotics.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pna-7", type: "question", question: "What is the CURB-65 score used for?", options: ["Diagnosing pneumonia", "Determining need for hospitalization in CAP", "Classifying pneumonia severity in ICU", "Predicting antibiotic resistance"], correctIndex: 1, answer: "CURB-65 assesses pneumonia severity and guides disposition: Confusion, Urea >20, RR >30, BP <90/60, age >65. Score 0-1: outpatient; 2: consider admission; 3+: hospital admission; 4-5: consider ICU.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-8", type: "question", question: "Vancomycin infused too rapidly causes:", options: ["Hepatotoxicity", "Red man syndrome (histamine-mediated flushing, not an allergy)", "Bone marrow suppression", "Seizures"], correctIndex: 1, answer: "Red man syndrome is caused by rapid vancomycin infusion triggering histamine release. It presents as flushing, erythema, and pruritus of the upper body. It is NOT an allergic reaction. Infuse over at least 60 minutes.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-9", type: "question", question: "What sputum finding is associated with Klebsiella pneumoniae?", options: ["Rust-colored sputum", "Currant jelly (thick, bloody, mucoid) sputum", "Watery sputum", "Pink frothy sputum"], correctIndex: 1, answer: "Klebsiella pneumoniae produces thick, bloody, mucoid sputum described as 'currant jelly.' It commonly affects alcoholics and immunocompromised patients and causes necrotizing pneumonia with cavity formation.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-10", type: "question", question: "A fluoroquinolone (levofloxacin) carries FDA boxed warnings for:", options: ["Hepatotoxicity only", "Tendon rupture, peripheral neuropathy, and CNS effects", "Renal failure", "Cardiac arrest"], correctIndex: 1, answer: "Fluoroquinolones carry FDA boxed warnings for tendon rupture (especially Achilles), peripheral neuropathy, and CNS effects. Risk is highest in patients >60 years, on corticosteroids, or with renal/liver/heart transplant.", category: "Respiratory", difficulty: 2 },

  // ============================================================
  // AKI (30 cards)
  // ============================================================
  { id: "rn-aki-1", type: "question", question: "BUN/Creatinine ratio >20:1 suggests which type of AKI?", options: ["Intrarenal", "Postrenal", "Prerenal", "Chronic kidney disease"], correctIndex: 2, answer: "Prerenal AKI shows BUN/Cr >20:1 because the underperfused but intact kidney reabsorbs urea proportionally more than creatinine. Intrarenal shows <15:1 (damaged tubules cannot selectively reabsorb urea).", category: "Renal", difficulty: 2 },
  { id: "rn-aki-2", type: "question", question: "What urinalysis finding is pathognomonic for acute tubular necrosis (ATN)?", options: ["RBC casts", "White blood cell casts", "Muddy brown granular casts", "Hyaline casts"], correctIndex: 2, answer: "Muddy brown granular casts are pathognomonic for ATN. They represent sloughed necrotic tubular epithelial cells. RBC casts = glomerulonephritis, WBC casts = pyelonephritis/interstitial nephritis.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-3", type: "question", question: "A patient with AKI has K+ 6.8 and peaked T waves. Which medication is given FIRST?", options: ["Kayexalate", "Regular insulin + D50W", "Calcium gluconate IV", "Furosemide"], correctIndex: 2, answer: "Calcium gluconate stabilizes cardiac membranes within 1-3 minutes, preventing fatal arrhythmias. It does NOT lower K+. It buys time while insulin/glucose (shifts K+) and kayexalate (removes K+) take effect.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-4", type: "question", question: "FENa <1% indicates:", options: ["Intrarenal AKI (ATN)", "Prerenal AKI (kidney appropriately retaining sodium)", "Postrenal obstruction", "Normal kidney function"], correctIndex: 1, answer: "Fractional excretion of sodium (FENa) <1% indicates prerenal AKI - the intact kidney is appropriately retaining sodium in response to decreased perfusion. FENa >2% indicates intrarenal damage (tubules cannot reabsorb sodium).", category: "Renal", difficulty: 3 },
  { id: "rn-aki-5", type: "question", question: "What is the mnemonic for dialysis indications in AKI?", options: ["FAST", "AEIOU: Acidosis, Electrolytes (hyperK), Ingestion, Overload, Uremia", "SIRS", "ABCDE"], correctIndex: 1, answer: "AEIOU: Acidosis (refractory), Electrolytes (hyperkalemia refractory to medical management), Ingestion (toxic substances), Overload (fluid overload unresponsive to diuretics), Uremia symptoms (pericarditis, encephalopathy).", category: "Renal", difficulty: 2 },
  { id: "rn-aki-6", type: "question", question: "What is the most life-threatening electrolyte abnormality in AKI?", options: ["Hyponatremia", "Hyperphosphatemia", "Hyperkalemia", "Hypocalcemia"], correctIndex: 2, answer: "Hyperkalemia is the most immediately life-threatening complication of AKI. Elevated potassium disrupts cardiac conduction, causing peaked T waves, widened QRS, and potentially fatal arrhythmias (V-fib, asystole).", category: "Renal", difficulty: 1 },
  { id: "rn-aki-7", type: "question", question: "Calcium gluconate does NOT lower potassium. What does it do?", options: ["Removes potassium from the body", "Stabilizes cardiac cell membranes against arrhythmias", "Shifts potassium into cells", "Increases renal potassium excretion"], correctIndex: 1, answer: "Calcium gluconate directly antagonizes the effect of hyperkalemia on cardiac cell membrane potential, restoring the normal threshold for depolarization. It provides cardioprotection while other treatments lower K+.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-8", type: "question", question: "A patient receives IV contrast for CT. What is the nurse's priority to prevent contrast-induced AKI?", options: ["Administer an antihistamine", "Ensure adequate pre- and post-procedure IV hydration", "Give oral activated charcoal", "Nothing - contrast is always safe"], correctIndex: 1, answer: "IV hydration before and after contrast administration is the primary prevention strategy for contrast-induced nephropathy. NS or isotonic bicarbonate dilutes the contrast and maintains renal perfusion.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-9", type: "question", question: "Uremic pericarditis (pericardial friction rub) in AKI indicates:", options: ["A mild complication requiring observation", "Severe uremia - likely indication for emergent dialysis", "Normal finding in kidney disease", "Need for anticoagulation"], correctIndex: 1, answer: "Uremic pericarditis (friction rub) is a serious complication indicating significant uremic toxin accumulation. It is an indication for emergent dialysis. Anticoagulation is generally AVOIDED due to risk of hemorrhagic pericarditis.", category: "Renal", difficulty: 3 },
  { id: "rn-aki-10", type: "question", question: "Creatinine is a lagging indicator. What does this mean clinically?", options: ["Creatinine rises before GFR declines", "Creatinine may not rise until GFR has already declined by 50%", "Creatinine is unreliable in all patients", "Creatinine should not be used to monitor AKI"], correctIndex: 1, answer: "Serum creatinine does not begin to rise above normal until GFR has declined by approximately 50%. This means significant kidney injury may be present before lab values become abnormal.", category: "Renal", difficulty: 2 },

  // ============================================================
  // CKD (25 cards)
  // ============================================================
  { id: "rn-ckd-1", type: "question", question: "What is the pathophysiological cascade of CKD mineral bone disease?", options: ["Low calcium -> high PTH -> bone loss", "High phosphorus -> low calcium -> high PTH -> bone resorption (renal osteodystrophy)", "High calcium -> low PTH -> bone formation", "Normal phosphorus -> normal calcium -> normal bones"], correctIndex: 1, answer: "Failing kidneys cannot excrete phosphate (hyperphosphatemia) which binds calcium (hypocalcemia) which stimulates PTH release (secondary hyperparathyroidism) which causes bone resorption (renal osteodystrophy).", category: "Renal", difficulty: 2 },
  { id: "rn-ckd-2", type: "question", question: "When should phosphate binders (sevelamer) be administered?", options: ["On an empty stomach in the morning", "WITH meals to bind dietary phosphorus in the GI tract", "At bedtime", "Only when phosphorus exceeds 8.0 mg/dL"], correctIndex: 1, answer: "Phosphate binders must be taken WITH meals because they work by binding dietary phosphorus in the GI tract, preventing absorption. Taking them on an empty stomach provides no benefit.", category: "Renal", difficulty: 1 },
  { id: "rn-ckd-3", type: "question", question: "What is the target hemoglobin for ESA therapy (epoetin alfa) in CKD?", options: ["12-14 g/dL (normalize hemoglobin)", "10-11.5 g/dL (do NOT normalize - FDA boxed warning)", "8-9 g/dL", "14-16 g/dL"], correctIndex: 1, answer: "FDA boxed warning: targeting Hgb >11 g/dL with ESAs increases cardiovascular events and mortality. Target is 10-11.5 g/dL. Also ensure adequate iron stores (ferritin >200, TSAT >20%) before starting ESAs.", category: "Renal", difficulty: 2 },
  { id: "rn-ckd-4", type: "question", question: "The nurse palpates an AV fistula and does NOT feel a thrill. What is the priority?", options: ["Document and recheck next shift", "Notify provider immediately - fistula may be clotted", "Apply a warm compress", "Auscultate for a bruit only"], correctIndex: 1, answer: "Absence of thrill (palpable vibration) and bruit (auscultated turbulent flow) indicates fistula thrombosis until proven otherwise. This is a time-sensitive emergency requiring immediate provider notification.", category: "Renal", difficulty: 2 },
  { id: "rn-ckd-5", type: "question", question: "Which access site has the lowest infection rate for hemodialysis?", options: ["Tunneled catheter", "Arteriovenous fistula (AVF)", "Arteriovenous graft", "Femoral catheter"], correctIndex: 1, answer: "The AV fistula (native vessel) has the lowest infection and complication rates. It is the preferred access but requires 6-8 weeks to mature before use. Grafts can be used in 2-3 weeks but have higher infection/thrombosis rates.", category: "Renal", difficulty: 1 },
  { id: "rn-ckd-6", type: "question", question: "What should the nurse NEVER do with the arm containing an AV fistula?", options: ["Palpate for thrill", "Auscultate for bruit", "Take blood pressure, draw blood, or place an IV in that arm", "Assess skin color and temperature"], correctIndex: 2, answer: "NEVER take BP, draw blood, or place IVs in the fistula arm. External compression from a BP cuff or tourniquet can damage or clot the fistula. This is a critical patient safety teaching point.", category: "Renal", difficulty: 1 },
  { id: "rn-ckd-7", type: "question", question: "Why is calcitriol (active vitamin D) given instead of regular vitamin D in CKD?", options: ["Regular vitamin D is more expensive", "CKD kidneys cannot convert 25-hydroxyvitamin D to active 1,25-dihydroxyvitamin D (calcitriol)", "Calcitriol has fewer side effects", "Regular vitamin D causes more hypercalcemia"], correctIndex: 1, answer: "The kidneys perform the final hydroxylation step converting 25-hydroxyvitamin D to active 1,25-dihydroxyvitamin D (calcitriol). In CKD, this enzyme is deficient, so the active form must be given directly.", category: "Renal", difficulty: 2 },
  { id: "rn-ckd-8", type: "question", question: "Ammonia breath (uremic fetor) in a CKD patient indicates:", options: ["Poor oral hygiene", "Significant uremia with urea breakdown to ammonia", "Diabetic ketoacidosis", "Liver failure"], correctIndex: 1, answer: "Uremic fetor (ammonia/urine-like breath) results from urea breakdown to ammonia by oral bacteria. It indicates significant uremia and may be accompanied by metallic taste and nausea/anorexia.", category: "Renal", difficulty: 2 },
  { id: "rn-ckd-9", type: "question", question: "What are the two leading causes of CKD in order?", options: ["Glomerulonephritis and polycystic kidney disease", "Diabetes mellitus (#1) and hypertension (#2)", "Lupus and IgA nephropathy", "Drug toxicity and infection"], correctIndex: 1, answer: "Diabetes mellitus (#1, ~44%) causes diabetic nephropathy. Hypertension (#2, ~28%) causes nephrosclerosis. Together they account for >70% of ESRD. Controlling both is the most important intervention.", category: "Renal", difficulty: 1 },
  { id: "rn-ckd-10", type: "question", question: "ACEi/ARBs are renoprotective in CKD because they:", options: ["Increase blood pressure to improve renal perfusion", "Dilate the efferent arteriole, reducing intraglomerular pressure and proteinuria", "Directly repair damaged nephrons", "Increase GFR above normal"], correctIndex: 1, answer: "ACEi/ARBs dilate the efferent arteriole, reducing intraglomerular pressure and decreasing protein leakage into urine. This slows CKD progression independently of their blood pressure effect.", category: "Renal", difficulty: 2 },

  // ============================================================
  // SODIUM IMBALANCES (25 cards)
  // ============================================================
  { id: "rn-na-1", type: "question", question: "What is the maximum safe correction rate for chronic hyponatremia?", options: ["4-6 mEq/L per 24 hours", "8-10 mEq/L per 24 hours", "15-20 mEq/L per 24 hours", "No limit - correct as fast as possible"], correctIndex: 1, answer: "Chronic hyponatremia must be corrected no faster than 8-10 mEq/L per 24 hours to prevent osmotic demyelination syndrome (central pontine myelinolysis). Monitor sodium q2-4h during correction.", category: "Renal", difficulty: 2 },
  { id: "rn-na-2", type: "question", question: "SIADH causes hyponatremia by:", options: ["Losing sodium in urine excessively", "Retaining too much water, diluting serum sodium", "Decreasing water intake", "Increasing aldosterone secretion"], correctIndex: 1, answer: "SIADH causes excess ADH, which promotes water retention by the collecting ducts. The excess water dilutes sodium (dilutional hyponatremia). The patient is euvolemic/mildly hypervolemic with concentrated urine.", category: "Renal", difficulty: 2 },
  { id: "rn-na-3", type: "question", question: "A post-neurosurgery patient produces 1L dilute urine in 2 hours with Na 154 and urine SG 1.002. What is the diagnosis?", options: ["SIADH", "Central diabetes insipidus", "Prerenal AKI", "Normal postoperative diuresis"], correctIndex: 1, answer: "Central DI after neurosurgery: massive dilute urine output (low SG <1.005), hypernatremia (water loss exceeds sodium), dehydration. Caused by damage to the posterior pituitary or hypothalamus.", category: "Renal", difficulty: 2 },
  { id: "rn-na-4", type: "question", question: "Osmotic demyelination syndrome (ODS) from rapid sodium correction presents with:", options: ["Seizures immediately during correction", "Dysarthria, dysphagia, and quadriparesis developing 2-6 days AFTER correction", "Hypertension and bradycardia", "Polyuria and polydipsia"], correctIndex: 1, answer: "ODS/central pontine myelinolysis presents 2-6 days after overly rapid correction of chronic hyponatremia. Myelin destruction causes locked-in syndrome, quadriparesis, dysarthria, and dysphagia. Often irreversible.", category: "Renal", difficulty: 3 },
  { id: "rn-na-5", type: "question", question: "3% hypertonic saline is administered via:", options: ["Any peripheral IV", "Central line with IV pump", "Subcutaneous injection", "IM injection"], correctIndex: 1, answer: "3% hypertonic saline should be administered via central line (due to high osmolality causing phlebitis) using an IV pump for precise rate control. Sodium must be monitored every 2 hours during infusion.", category: "Renal", difficulty: 2 },

  // ============================================================
  // POTASSIUM IMBALANCES (25 cards)
  // ============================================================
  { id: "rn-k-1", type: "question", question: "What ECG finding is pathognomonic for hypokalemia?", options: ["Peaked T waves", "U waves", "Widened QRS", "ST elevation"], correctIndex: 1, answer: "U waves (small deflection after the T wave) are pathognomonic for hypokalemia. Other findings include flattened T waves, ST depression, and prolonged QT interval.", category: "Renal", difficulty: 1 },
  { id: "rn-k-2", type: "question", question: "IV potassium given too rapidly or undiluted can cause:", options: ["Hypertension", "Fatal cardiac arrest", "Seizures", "Anaphylaxis"], correctIndex: 1, answer: "IV potassium KILLS if given too fast. It causes fatal cardiac arrest from sudden hyperkalemia at the heart. NEVER give IV push. Maximum peripheral rate: 10-20 mEq/hr with cardiac monitoring.", category: "Renal", difficulty: 1 },
  { id: "rn-k-3", type: "question", question: "Why must hypomagnesemia be corrected before hypokalemia?", options: ["They are unrelated", "Magnesium is needed for Na+/K+-ATPase function; hypokalemia is refractory without adequate Mg2+", "Magnesium directly raises potassium", "It is just a traditional practice"], correctIndex: 1, answer: "Magnesium is required for proper Na+/K+-ATPase pump function. Without adequate Mg2+, potassium leaks out of cells through ROMK channels, making K+ replacement futile. Always check and correct Mg2+ first.", category: "Renal", difficulty: 2 },
  { id: "rn-k-4", type: "question", question: "How do pH and potassium levels relate?", options: ["They move in the same direction", "They move in opposite directions (acidosis = hyperK, alkalosis = hypoK)", "They are unrelated", "Only pH affects potassium, not vice versa"], correctIndex: 1, answer: "pH and K+ have an inverse relationship through H+/K+ exchange. In acidosis, excess H+ moves into cells while K+ moves out (hyperkalemia). In alkalosis, H+ moves out and K+ moves in (hypokalemia). Each 0.1 pH change alters K+ by ~0.3-0.5.", category: "Renal", difficulty: 2 },
  { id: "rn-k-5", type: "question", question: "A patient on digoxin has K+ 3.0. What is the critical concern?", options: ["Digoxin will become less effective", "Hypokalemia potentiates digoxin toxicity - risk of fatal arrhythmia", "No significant interaction exists", "Potassium will increase digoxin absorption"], correctIndex: 1, answer: "Hypokalemia and digoxin compete for the same Na+/K+-ATPase binding site. Low K+ allows more digoxin to bind, potentiating toxicity (visual changes, nausea, bradycardia, arrhythmias). Monitor K+ closely.", category: "Renal", difficulty: 2 },

  // ============================================================
  // CALCIUM/PHOSPHATE (25 cards)
  // ============================================================
  { id: "rn-ca-1", type: "question", question: "A patient 8 hours post-thyroidectomy reports perioral tingling. The nurse taps the facial nerve and observes facial twitching. What sign is this?", options: ["Kernig sign", "Brudzinski sign", "Chvostek sign indicating hypocalcemia", "Babinski sign"], correctIndex: 2, answer: "Chvostek sign = facial twitching when tapping the facial nerve anterior to the ear. Post-thyroidectomy hypocalcemia occurs from inadvertent parathyroid gland damage. Have IV calcium gluconate at bedside.", category: "Renal", difficulty: 1 },
  { id: "rn-ca-2", type: "question", question: "Trousseau sign is elicited by:", options: ["Tapping the facial nerve", "Inflating a BP cuff above systolic for 3 minutes - positive = carpal spasm", "Flexing the neck", "Extending the knee"], correctIndex: 1, answer: "Trousseau sign: BP cuff inflated above systolic for 3 minutes causes carpal spasm (hand/wrist flexion). It is MORE specific than Chvostek sign for hypocalcemia.", category: "Renal", difficulty: 1 },
  { id: "rn-ca-3", type: "question", question: "The mnemonic for hypercalcemia symptoms is:", options: ["MUDPILES", "AEIOU", "Bones, Stones, Groans, and Psychiatric Overtones", "FAST"], correctIndex: 2, answer: "Hypercalcemia: Bones (pain, fractures), Stones (kidney stones), Groans (abdominal pain, constipation, nausea), Psychiatric Overtones (confusion, lethargy, depression, psychosis).", category: "Renal", difficulty: 1 },
  { id: "rn-ca-4", type: "question", question: "Calcium chloride 10% must ONLY be given via:", options: ["Any IV", "Central line only (caustic to peripheral veins)", "Subcutaneous", "Intramuscular"], correctIndex: 1, answer: "Calcium chloride is highly caustic and causes severe tissue necrosis if it extravasates from a peripheral IV. Central line ONLY. Calcium gluconate is preferred for peripheral IV administration.", category: "Renal", difficulty: 2 },
  { id: "rn-ca-5", type: "question", question: "Why does alkalosis cause tetany similar to hypocalcemia?", options: ["Alkalosis destroys calcium", "Alkalosis increases calcium binding to albumin, reducing physiologically active ionized calcium", "Alkalosis increases renal calcium excretion", "There is no relationship"], correctIndex: 1, answer: "In alkalosis, H+ leaves albumin, freeing binding sites for calcium. More calcium binds to albumin, reducing the ionized (active) fraction. Although total calcium may be normal, decreased ionized calcium causes tetany.", category: "Renal", difficulty: 3 },

  // ============================================================
  // ACID-BASE (30 cards)
  // ============================================================
  { id: "rn-ab-1", type: "question", question: "ABG: pH 7.18, PaCO2 24, HCO3 8, AG 30. Patient has deep rapid respirations and fruity breath. Diagnosis?", options: ["Respiratory acidosis", "Anion gap metabolic acidosis - DKA", "Metabolic alkalosis", "Respiratory alkalosis"], correctIndex: 1, answer: "Low pH + low HCO3 = metabolic acidosis. Low PaCO2 = respiratory compensation (Kussmaul). AG = 30 (elevated). Fruity breath (acetone) + elevated AG = DKA.", category: "Renal", difficulty: 2 },
  { id: "rn-ab-2", type: "question", question: "MUDPILES mnemonic lists causes of:", options: ["Respiratory alkalosis", "Non-anion gap metabolic acidosis", "Anion gap metabolic acidosis", "Metabolic alkalosis"], correctIndex: 2, answer: "MUDPILES = anion gap metabolic acidosis causes: Methanol, Uremia, DKA, Propylene glycol/Paraldehyde, Isoniazid/Iron, Lactic acidosis, Ethylene glycol, Salicylates.", category: "Renal", difficulty: 1 },
  { id: "rn-ab-3", type: "question", question: "In DKA, when should insulin be started?", options: ["Immediately regardless of K+", "Only after K+ is confirmed >=3.3 mEq/L", "After blood glucose normalizes", "After bicarbonate is given"], correctIndex: 1, answer: "Insulin must NOT be started until K+ >=3.3 because insulin drives K+ intracellularly. Starting insulin with low K+ can cause fatal hypokalemia and cardiac arrest. Replace K+ first if <3.3.", category: "Renal", difficulty: 2 },
  { id: "rn-ab-4", type: "question", question: "A patient with prolonged NG suction has pH 7.52, HCO3 38, K+ 2.9. The acid-base disorder is:", options: ["Metabolic acidosis", "Chloride-responsive metabolic alkalosis from HCl loss", "Respiratory alkalosis", "Mixed disorder"], correctIndex: 1, answer: "NG suction removes HCl from the stomach, causing loss of H+ and Cl-. The resulting metabolic alkalosis is chloride-responsive (urine Cl- <20). Treat with IV NS (provides Cl-) and KCl.", category: "Renal", difficulty: 2 },
  { id: "rn-ab-5", type: "question", question: "Winter formula (PaCO2 = 1.5 x HCO3 + 8 +/-2) is used to:", options: ["Calculate anion gap", "Determine expected respiratory compensation in metabolic acidosis", "Predict renal compensation", "Calculate osmolality"], correctIndex: 1, answer: "Winter formula predicts expected PaCO2 for the degree of metabolic acidosis. If actual PaCO2 > predicted, a concurrent respiratory acidosis exists. If < predicted, a concurrent respiratory alkalosis exists.", category: "Renal", difficulty: 3 },
  { id: "rn-ab-6", type: "question", question: "A normal pH with abnormal PaCO2 and HCO3 means:", options: ["Normal acid-base status", "Two opposing disorders masking each other (mixed disorder with compensated pH)", "Lab error", "Full compensation of a single disorder OR a mixed disorder"], correctIndex: 3, answer: "Normal pH with abnormal values can indicate either full compensation of a single disorder OR two opposing primary disorders. Clinical context and calculating expected compensation helps differentiate.", category: "Renal", difficulty: 3 },
  { id: "rn-ab-7", type: "question", question: "Kussmaul breathing is the body's compensation for:", options: ["Respiratory acidosis", "Metabolic acidosis (deep rapid breaths blow off CO2 to raise pH)", "Metabolic alkalosis", "Respiratory alkalosis"], correctIndex: 1, answer: "Kussmaul breathing = deep, rapid respirations. The lungs blow off CO2 (volatile acid) to partially compensate for metabolic acidosis. It is particularly prominent in DKA.", category: "Renal", difficulty: 1 },
  { id: "rn-ab-8", type: "question", question: "Salicylate overdose uniquely causes:", options: ["Pure metabolic acidosis", "Pure respiratory alkalosis", "Mixed respiratory alkalosis AND metabolic acidosis", "Pure metabolic alkalosis"], correctIndex: 2, answer: "Salicylates directly stimulate the medullary respiratory center (respiratory alkalosis) AND cause metabolic acidosis (lactic acid, ketoacids, uncoupled oxidative phosphorylation). This unique mixed pattern is characteristic.", category: "Renal", difficulty: 3 },
  { id: "rn-ab-9", type: "question", question: "Diarrhea causes which type of metabolic acidosis?", options: ["Anion gap metabolic acidosis", "Non-anion gap (hyperchloremic) metabolic acidosis", "Respiratory acidosis", "Metabolic alkalosis"], correctIndex: 1, answer: "Diarrhea causes direct bicarbonate loss from intestinal secretions. Chloride is retained to maintain electrical neutrality, resulting in hyperchloremic non-anion gap metabolic acidosis.", category: "Renal", difficulty: 2 },
  { id: "rn-ab-10", type: "question", question: "Respiratory compensation for metabolic disorders is:", options: ["Slow (3-5 days)", "Rapid (minutes to hours)", "Never occurs", "Only occurs with medication"], correctIndex: 1, answer: "Respiratory compensation is rapid (minutes to hours) because it only requires changes in ventilation rate/depth. Renal compensation for respiratory disorders is slow (3-5 days) because it requires changes in H+ secretion and HCO3 regeneration.", category: "Renal", difficulty: 1 },
];
